import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const {
    gem_prediction,
    gem_confidence,
    shape_prediction,
    shape_confidence,
    image,
    show_shape,
  } = location.state || {};

  const gemConfidencePercent = (gem_confidence * 100).toFixed(1);
  const shapeConfidencePercent = show_shape ? (shape_confidence * 100).toFixed(1) : null;

  return (
    <>
      <Topnav />

      <main className="min-h-screen bg-gradient-to-b from-[#0a1425] via-[#0f1a36] to-[#0a1425] text-slate-100 pt-8 pb-16">
        <div className="max-w-5xl mx-auto px-6">
          {/* Header / Title */}
          <div className="text-center mb-12 md:mb-16">
            <h1 className="text-4xl md:text-5xl font-bold tracking-tight text-[#60a5fa] mb-3">
              Gem Analysis Result
            </h1>
            <p className="text-lg md:text-xl text-slate-400">
              Powered by advanced AI image recognition
            </p>
          </div>

          {/* Main Result Card */}
          <div className="bg-[#111d38]/70 backdrop-blur-md border border-[#1e40af]/40 rounded-3xl overflow-hidden shadow-2xl shadow-black/60">
            {/* Large Gem Image */}
            {image && (
              <div className="relative aspect-square md:aspect-[4/3] overflow-hidden bg-black/40">
                <img
                  src={URL.createObjectURL(image)}
                  alt={`${gem_prediction || "Gem"}`}
                  className="w-full h-full object-contain transition-transform duration-700 hover:scale-105"
                />
                {/* Subtle glow overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-black/20 pointer-events-none"></div>
              </div>
            )}

            {/* Result Content */}
            <div className="p-8 md:p-12 text-center">
              <h2 className="text-5xl md:text-6xl font-extrabold text-[#60a5fa] mb-4 tracking-tight">
                {gem_prediction || "Unknown Gem"}
              </h2>

              <div className="space-y-6 mt-8 text-lg md:text-xl">
                <div>
                  <div className="text-slate-300 mb-1">Gem Identification</div>
                  <div className="text-2xl font-semibold text-white">
                    {gem_prediction}
                  </div>
                  <div className="mt-2 inline-block px-5 py-1.5 bg-[#1e40af]/40 rounded-full text-[#60a5fa] font-medium">
                    Confidence: {gemConfidencePercent}%
                  </div>
                </div>

                {show_shape && shape_prediction && (
                  <div>
                    <div className="text-slate-300 mb-1">Shape / Cut</div>
                    <div className="text-2xl font-semibold text-white">
                      {shape_prediction}
                    </div>
                    <div className="mt-2 inline-block px-5 py-1.5 bg-[#1e40af]/40 rounded-full text-[#60a5fa] font-medium">
                      Confidence: {shapeConfidencePercent}%
                    </div>
                  </div>
                )}
              </div>

              {/* Re-Analyze Button */}
              <button
                onClick={() => navigate("/imageuploader")}
                className="mt-12 px-10 py-4 bg-[#3b82f6] hover:bg-[#2563eb] text-white text-lg font-semibold rounded-full transition-all duration-300 shadow-lg shadow-[#3b82f6]/30 hover:shadow-xl hover:shadow-[#3b82f6]/50 transform hover:scale-105 focus:outline-none focus:ring-4 focus:ring-[#60a5fa]/40"
              >
                Re-Analyze Another Gem
              </button>
            </div>
          </div>

          {/* Optional small footer note */}
          <p className="text-center text-slate-500 mt-10 text-sm">
            Results are AI-generated estimates • For professional appraisal consult a certified gemologist
          </p>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default Result;
